// NetworkModule.kt
object NetworkModule {
    private const val DEV_BASE_URL = "https://dev.api.example.com/"
    private const val STAGING_BASE_URL = "https://staging.api.example.com/"
    private const val PROD_BASE_URL = "https://api.example.com/"

    private fun getBaseUrl(): String {
        return when (BuildConfig.BUILD_TYPE) {
            "debug" -> DEV_BASE_URL
            "staging" -> STAGING_BASE_URL
            else -> PROD_BASE_URL
        }
    }

    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }

    private val okHttpClient = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .addInterceptor { chain ->
            val request = chain.request().newBuilder()
                .addHeader("Authorization", "Bearer YOUR_AUTH_TOKEN")
                .build()
            chain.proceed(request)
        }
        .build()

    val retrofit: Retrofit = Retrofit.Builder()
        .baseUrl(getBaseUrl())
        .client(okHttpClient)
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    val apiService: ApiService = retrofit.create(ApiService::class.java)
